function solve(grid, x, y, k) {
    const newGrid = grid.map(row => [...row]);
    const submatrixRows = [];
    for (let i = 0; i < k; i++) {
        const row = newGrid[x + i].slice(y, y + k);
        submatrixRows.push(row);
    }
    submatrixRows.reverse();
    for (let i = 0; i < k; i++) {
        const originalRow = newGrid[x + i];
        const newSubRow = submatrixRows[i];
        const newRow = originalRow.slice(0, y).concat(newSubRow).concat(originalRow.slice(y + k));
        newGrid[x + i] = newRow;
    }
    return newGrid;
}
